import{_ as i,C as s,o as n,c as d,j as o,a,E as r,ai as c}from"./chunks/framework.-fuqNImP.js";const P=JSON.parse('{"title":"Go Pro","description":"","frontmatter":{},"headers":[],"relativePath":"courses/go-pro.md","filePath":"courses/go-pro.md"}'),l={name:"courses/go-pro.md"};function p(h,e,u,g,m,b){const t=s("Badge");return n(),d("div",null,[e[0]||(e[0]=o("h1",{id:"go-pro",tabindex:"-1"},[a("Go Pro "),o("a",{class:"header-anchor",href:"#go-pro","aria-label":'Permalink to "Go Pro"'},"​")],-1)),r(t,{type:"danger",text:"Advanced"}),e[1]||(e[1]=a()),r(t,{type:"info",text:"11 Modules"}),e[2]||(e[2]=a()),r(t,{type:"tip",text:"Partial"}),e[3]||(e[3]=c('<p>Advanced Playwright topics for team leads and senior automation engineers. Trace viewer mastery, mobile testing, parallel execution, GitHub Actions CI/CD, and emerging tools.</p><h2 id="course-overview" tabindex="-1">Course Overview <a class="header-anchor" href="#course-overview" aria-label="Permalink to &quot;Course Overview&quot;">​</a></h2><p>Go Pro covers the scale and advanced tiers of the curriculum (modules 22–32). These modules assume familiarity with Playwright fundamentals and focus on production-grade practices.</p><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p>Complete <a href="/midnight-automation-voyage/courses/build-skills">Build Skills</a> or have equivalent experience with Playwright page objects, auth fixtures, and CI/CD basics.</p></div><h2 id="module-breakdown" tabindex="-1">Module Breakdown <a class="header-anchor" href="#module-breakdown" aria-label="Permalink to &quot;Module Breakdown&quot;">​</a></h2><h3 id="_22-trace-viewer" tabindex="-1">22. Trace Viewer <a class="header-anchor" href="#_22-trace-viewer" aria-label="Permalink to &quot;22. Trace Viewer&quot;">​</a></h3><p>Deep dive into Playwright&#39;s trace viewer. Capture traces, analyze step-by-step execution, inspect network calls, and debug failures visually.</p><h3 id="_23-mobile-and-responsive-testing" tabindex="-1">23. Mobile and Responsive Testing <a class="header-anchor" href="#_23-mobile-and-responsive-testing" aria-label="Permalink to &quot;23. Mobile and Responsive Testing&quot;">​</a></h3><p>Device emulation, viewport configuration, and touch event simulation. Test responsive layouts across phone, tablet, and desktop breakpoints.</p><h3 id="_24-parallel-execution-and-sharding" tabindex="-1">24. Parallel Execution and Sharding <a class="header-anchor" href="#_24-parallel-execution-and-sharding" aria-label="Permalink to &quot;24. Parallel Execution and Sharding&quot;">​</a></h3><p>Run tests across multiple workers and machines. <code>fullyParallel</code>, <code>--shard</code>, and CI matrix strategies for fast feedback.</p><h3 id="_25-multi-browser-projects" tabindex="-1">25. Multi-Browser Projects <a class="header-anchor" href="#_25-multi-browser-projects" aria-label="Permalink to &quot;25. Multi-Browser Projects&quot;">​</a></h3><p>Configure Playwright projects for Chromium, Firefox, and WebKit. Browser-specific selectors, platform differences, and cross-browser CI.</p><h3 id="_26-test-tagging" tabindex="-1">26. Test Tagging <a class="header-anchor" href="#_26-test-tagging" aria-label="Permalink to &quot;26. Test Tagging&quot;">​</a></h3><p>Organize tests with tags — <code>@smoke</code>, <code>@regression</code>, <code>@critical</code>. Filter test runs by tag, combine tags, and integrate with CI pipelines.</p><h3 id="_27-github-actions" tabindex="-1">27. GitHub Actions <a class="header-anchor" href="#_27-github-actions" aria-label="Permalink to &quot;27. GitHub Actions&quot;">​</a></h3><p>Production-ready CI/CD configuration. Caching, artifacts, matrix builds, scheduled runs, and Playwright-specific GitHub Actions patterns.</p><h3 id="_28-mcp-and-ai-agents" tabindex="-1">28. MCP and AI Agents <a class="header-anchor" href="#_28-mcp-and-ai-agents" aria-label="Permalink to &quot;28. MCP and AI Agents&quot;">​</a></h3><p>Emerging patterns — Model Context Protocol for test generation, AI-powered test maintenance, and agent-based testing workflows.</p><h3 id="_29-component-testing" tabindex="-1">29. Component Testing <a class="header-anchor" href="#_29-component-testing" aria-label="Permalink to &quot;29. Component Testing&quot;">​</a></h3><p>Test React components in isolation with Playwright&#39;s experimental component testing. Setup, mounting, and assertions without a full app server.</p><h3 id="_30-performance-testing" tabindex="-1">30. Performance Testing <a class="header-anchor" href="#_30-performance-testing" aria-label="Permalink to &quot;30. Performance Testing&quot;">​</a></h3><p>Measure and assert on web performance metrics. Core Web Vitals, network timing, and custom performance budgets with Playwright.</p><h3 id="_31-custom-reporters" tabindex="-1">31. Custom Reporters <a class="header-anchor" href="#_31-custom-reporters" aria-label="Permalink to &quot;31. Custom Reporters&quot;">​</a></h3><p>Build custom Playwright reporters. JSON, HTML, and API integrations for test management tools. Reporter lifecycle hooks.</p><h3 id="_32-complex-dom-interactions" tabindex="-1">32. Complex DOM Interactions <a class="header-anchor" href="#_32-complex-dom-interactions" aria-label="Permalink to &quot;32. Complex DOM Interactions&quot;">​</a></h3><p>Advanced interaction patterns — drag and drop, file uploads, iframes, shadow DOM, and canvas elements.</p><h2 id="topic-categories" tabindex="-1">Topic Categories <a class="header-anchor" href="#topic-categories" aria-label="Permalink to &quot;Topic Categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Modules</th><th>Focus</th></tr></thead><tbody><tr><td>Debugging</td><td>22</td><td>Trace analysis</td></tr><tr><td>Cross-platform</td><td>23, 25</td><td>Mobile, multi-browser</td></tr><tr><td>Scale</td><td>24, 26, 27</td><td>Parallel, tagging, CI/CD</td></tr><tr><td>Emerging</td><td>28</td><td>AI/MCP integration</td></tr><tr><td>Specialized</td><td>29, 30, 31, 32</td><td>Components, perf, reporters, DOM</td></tr></tbody></table><h2 id="reference-test-suite" tabindex="-1">Reference Test Suite <a class="header-anchor" href="#reference-test-suite" aria-label="Permalink to &quot;Reference Test Suite&quot;">​</a></h2><p>The <code>test-cases/examples/</code> directory contains 10 reference spec files with 59 total tests:</p><table tabindex="0"><thead><tr><th>Spec</th><th>Tests</th><th>Patterns Demonstrated</th></tr></thead><tbody><tr><td><code>accessibility.spec.ts</code></td><td>4</td><td>axe-core integration, WCAG checks</td></tr><tr><td><code>activity.spec.ts</code></td><td>5</td><td>Async content, filters, detail views</td></tr><tr><td><code>admin.spec.ts</code></td><td>7</td><td>Role-gated access, bulk operations</td></tr><tr><td><code>checkout.spec.ts</code></td><td>6</td><td>Multi-step wizard, data preservation</td></tr><tr><td><code>contact.spec.ts</code></td><td>7</td><td>Form validation, required fields</td></tr><tr><td><code>login.spec.ts</code></td><td>7</td><td>Auth flow, error handling, lockout</td></tr><tr><td><code>orders.spec.ts</code></td><td>6</td><td>Table operations, sorting, pagination</td></tr><tr><td><code>search.spec.ts</code></td><td>7</td><td>Search, filtering, empty states</td></tr><tr><td><code>settings.spec.ts</code></td><td>6</td><td>Tabbed interface, profile updates</td></tr><tr><td><code>toast.spec.ts</code></td><td>4</td><td>Notification timing, race conditions</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/midnight-automation-voyage/reference/architecture">Architecture Reference</a> — platform design decisions and ADRs</li><li><a href="/midnight-automation-voyage/reference/test-cases">Test Cases Reference</a> — detailed reference spec documentation</li></ul>',34))])}const w=i(l,[["render",p]]);export{P as __pageData,w as default};
